<script setup lang="ts">
import { ref } from 'vue'; import { useRouter } from 'vue-router'; import { useAuthStore } from '@/stores/auth'
const name=ref(''); const email=ref(''); const password=ref(''); const auth=useAuthStore(); const router=useRouter(); const sending=ref(false)
async function submit(){sending.value=true; const ok=await auth.signUp(name.value,email.value,password.value,'ciudadano'); if(ok&&auth.isAuthenticated) await router.push('/app'); sending.value=false}
</script>
<template><div class="auth-page"><router-link to="/" class="back">← Volver</router-link><div class="auth-card"><div class="auth-brand"><span>✚</span><h1>Crear cuenta</h1><p>Registra una cuenta ciudadana. Los roles de operador y administrador se asignan desde la base de datos.</p></div><form @submit.prevent="submit"><div class="form-group"><label>Nombre completo</label><input v-model="name" class="form-input" required/></div><div class="form-group"><label>Correo</label><input v-model="email" type="email" class="form-input" required/></div><div class="form-group"><label>Contraseña</label><input v-model="password" type="password" minlength="8" class="form-input" required/></div><p v-if="auth.error" class="form-error">{{auth.error}}</p><p v-if="auth.infoMessage" class="info">{{auth.infoMessage}}</p><button class="btn btn-primary w-full" :disabled="sending">{{sending?'Creando...':'Crear cuenta'}}</button></form><p class="bottom">¿Ya tienes cuenta? <router-link to="/login">Ingresar</router-link></p></div></div></template>
<style scoped>.auth-page{min-height:100vh;background:linear-gradient(135deg,#082f49,#0e7490);display:grid;place-items:center;padding:1rem}.back{position:fixed;top:1rem;left:1rem;color:#fff}.auth-card{width:min(450px,100%);background:#fff;border-radius:18px;padding:2rem}.auth-brand{text-align:center;margin-bottom:1.5rem}.auth-brand span{display:grid;place-items:center;width:52px;height:52px;margin:auto;background:#2dd4bf;border-radius:14px;font-size:1.6rem}.auth-brand h1{color:#082f49;margin:.6rem}.auth-brand p,.bottom{font-size:.82rem;color:#64748b}.info{font-size:.8rem;color:#166534;background:#dcfce7;padding:.6rem;border-radius:8px;margin-bottom:.8rem}.bottom{text-align:center;margin-top:1rem}</style>
